"use client"

import { useEffect, useState } from "react"
import { Clock, Plus, Zap, Factory, Beaker } from "lucide-react"
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card"
import { Badge } from "@/components/ui/badge"
import { Button } from "@/components/ui/button"
import { Skeleton } from "@/components/ui/skeleton"
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from "@/components/ui/table"
import { addToProductStock } from "@/app/actions"

interface ProductionBatch {
  id: string
  batch_number: string
  status: "PLANNING" | "FRYING" | "PACKAGING" | "COMPLETED"
  input_weight_kg: string | number
  output_weight_kg: string | number
  waste_weight_kg: string | number
  createdAt: string
  updatedAt: string
}

export default function Dashboard() {
  const [currentTime, setCurrentTime] = useState<string>("")
  const [batches, setBatches] = useState<ProductionBatch[]>([])
  const [isLoading, setIsLoading] = useState(true)
  const [stats, setStats] = useState({
    rawStock: 0,
    activeBatches: 0,
    coldStorage: 0,
    pendingOrders: 0,
  })

  // Real-time clock
  useEffect(() => {
    const updateClock = () => {
      const now = new Date()
      setCurrentTime(
        now.toLocaleTimeString("en-US", {
          hour: "2-digit",
          minute: "2-digit",
          second: "2-digit",
        })
      )
    }
    updateClock()
    const interval = setInterval(updateClock, 1000)
    return () => clearInterval(interval)
  }, [])

  // Fetch data from API
  useEffect(() => {
    const fetchData = async () => {
      try {
        setIsLoading(true)
        const response = await fetch("/api/dashboard")
        if (response.ok) {
          const data = await response.json()
          setBatches(data.batches || [])
          setStats(data.stats || {})
        }
      } catch (error) {
        console.error("Failed to fetch dashboard data:", error)
      } finally {
        setIsLoading(false)
      }
    }

    // Simulate data loading - replace with real API call
    const timer = setTimeout(() => {
      setIsLoading(false)
    }, 1500)

    fetchData()
    return () => clearTimeout(timer)
  }, [])

  const getStatusColor = (status: string) => {
    switch (status) {
      case "COMPLETED":
        return "bg-emerald-500/20 text-emerald-400 border-emerald-500/30"
      case "FRYING":
      case "PACKAGING":
        return "bg-amber-500/20 text-amber-400 border-amber-500/30"
      case "PLANNING":
        return "bg-blue-500/20 text-blue-400 border-blue-500/30"
      default:
        return "bg-zinc-500/20 text-zinc-400 border-zinc-500/30"
    }
  }

  const StatCard = ({ title, value, loading }: { title: string; value: string | number; loading: boolean }) => (
    <div className="glass-card p-6">
      <p className="text-sm font-medium text-zinc-300 mb-2">{title}</p>
      {loading ? (
        <Skeleton className="h-8 w-16 bg-zinc-800" />
      ) : (
        <p className="text-3xl font-bold text-emerald-400">{value}</p>
      )}
    </div>
  )

  return (
    <div className="p-8">
      {/* Header */}
      <div className="flex items-center justify-between mb-8">
        <div>
          <h1 className="text-4xl font-bold text-white mb-2">Fries Control v1.0</h1>
          <p className="text-zinc-400">Factory Command Center</p>
        </div>
        <div className="flex items-center gap-4 glass-card px-6 py-4">
          <Clock className="w-6 h-6 text-emerald-400" />
          <div>
            <p className="text-xs text-zinc-400">Current Time</p>
            <p className="text-2xl font-mono font-bold text-white">{currentTime}</p>
          </div>
        </div>
      </div>

      {/* Stats Grid */}
      <div className="grid-stats mb-8">
        <StatCard title="Raw Stock (kg)" value={stats.rawStock} loading={isLoading} />
        <StatCard title="Active Batches" value={stats.activeBatches} loading={isLoading} />
        <StatCard title="Cold Storage (units)" value={stats.coldStorage} loading={isLoading} />
        <StatCard title="Pending Orders" value={stats.pendingOrders} loading={isLoading} />
      </div>

      {/* Active Operations */}
      <div className="glass-card">
        <div className="p-6 border-b border-white/10">
          <div className="flex items-center justify-between">
            <div>
              <h2 className="text-xl font-bold text-white flex items-center gap-2">
                <Zap className="w-5 h-5 text-emerald-400" />
                Active Factory Lines
              </h2>
              <p className="text-sm text-zinc-400 mt-1">Production batches in progress</p>
            </div>
            <Button className="bg-emerald-600 hover:bg-emerald-700 text-white">
              <Plus className="w-4 h-4 mr-2" />
              New Batch
            </Button>
          </div>
        </div>

        {/* Table or Zero State */}
        {isLoading ? (
          <div className="p-6">
            <div className="space-y-3">
              {[1, 2, 3].map((i) => (
                <Skeleton key={i} className="h-12 w-full bg-zinc-800" />
              ))}
            </div>
          </div>
        ) : batches.length === 0 ? (
          // Zero State
          <div className="p-12 flex flex-col items-center justify-center">
            <div className="w-16 h-16 glass-card rounded-full flex items-center justify-center mb-4">
              <Factory className="w-8 h-8 text-zinc-500" />
            </div>
            <h3 className="text-xl font-bold text-white mb-2">No Active Factory Lines</h3>
            <p className="text-zinc-400 text-center mb-6 max-w-md">
              All production lines are currently idle. Start a new batch to begin manufacturing.
            </p>
            <Button className="bg-emerald-600 hover:bg-emerald-700 text-white">
              <Plus className="w-4 h-4 mr-2" />
              Launch New Batch
            </Button>
          </div>
        ) : (
          // Table
          <div className="overflow-x-auto">
            <Table>
              <TableHeader>
                <TableRow className="border-white/10 hover:bg-transparent">
                  <TableHead className="text-zinc-300">Batch #</TableHead>
                  <TableHead className="text-zinc-300">Status</TableHead>
                  <TableHead className="text-zinc-300 text-right">Input (kg)</TableHead>
                  <TableHead className="text-zinc-300 text-right">Output (kg)</TableHead>
                  <TableHead className="text-zinc-300 text-right">Waste (kg)</TableHead>
                  <TableHead className="text-zinc-300">Started</TableHead>
                </TableRow>
              </TableHeader>
              <TableBody>
                {batches.map((batch) => (
                  <TableRow key={batch.id} className="border-white/5 hover:bg-white/5">
                    <TableCell className="font-mono text-white">{batch.batch_number}</TableCell>
                    <TableCell>
                      <Badge variant="outline" className={`${getStatusColor(batch.status)} border`}>
                        {batch.status}
                      </Badge>
                    </TableCell>
                    <TableCell className="text-right text-zinc-300">{Number(batch.input_weight_kg).toFixed(2)}</TableCell>
                    <TableCell className="text-right text-zinc-300">{Number(batch.output_weight_kg).toFixed(2)}</TableCell>
                    <TableCell className="text-right text-zinc-300">{Number(batch.waste_weight_kg).toFixed(2)}</TableCell>
                    <TableCell className="text-zinc-400 text-sm">
                      {new Date(batch.createdAt).toLocaleDateString()}
                    </TableCell>
                  </TableRow>
                ))}
              </TableBody>
            </Table>
          </div>
        )}
      </div>
    </div>
  )
}
